#include <stdio.h>
#include <math.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    const long double phi = (1.0L + sqrtl(5.0L)) / 2.0L;
    while (T--) {
        int m, n, p, q;
        scanf("%d %d %d %d", &m, &n, &p, &q);
        int dx = m - p;
        int dy = n - q;
        int a = dx < dy ? dx : dy;
        int b = dx < dy ? dy : dx;
        int k = b - a;
        long double prod = k * phi;
        int t = (int)floorl(prod);
        if (t == a) {
            printf("Bob\n");
        } else {
            printf("Alice\n");
        }
    }
    return 0;
}

