    int T;
    if (!(cin >> T)) return 0;
    const long double phi = (1.0L + sqrtl(5.0L)) / 2.0L;
    while (T--) {
        long long m, n, p, q;
        cin >> m >> n >> p >> q;
        long long dx = m - p;
        long long dy = n - q;
        long long a = min(dx, dy);
        long long b = max(dx, dy);
        long long k = b - a;
        long long t = (long long)floorl(k * phi);
        if (t == a) cout << "Bob\n";
        else cout << "Alice\n";
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        final double phi = (1.0 + Math.sqrt(5.0)) / 2.0;
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < T; i++) {
            st = new StringTokenizer(br.readLine());
            long m = Long.parseLong(st.nextToken());
            long n = Long.parseLong(st.nextToken());
            long p = Long.parseLong(st.nextToken());
            long q = Long.parseLong(st.nextToken());
            long dx = m - p;
            long dy = n - q;
            long a = Math.min(dx, dy);
            long b = Math.max(dx, dy);
            long k = b - a;
            long t = (long) Math.floor(k * phi);
            sb.append(t == a ? "Bob" : "Alice");
            if (i + 1 < T) sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

